# db/seeds.rb
# Reduced full seed data.
# Includes every table found in your original seeds.rb:
# Department, User, DepartmentSemester, Subject, Student, StudentMark, InternalMark, ExternalMark
# Rule used: 10 students per department and 10 associated mark rows per student.

# Optional: clean existing data to avoid duplicates when running rails db:seed multiple times.
# Delete child tables first because of associations.
[
  StudentMark,
  InternalMark,
  ExternalMark,
  Student,
  Subject,
  DepartmentSemester,
  User,
  Department
].each do |model|
  model.delete_all
end

DEFAULT_PASSWORD = "121212"

# -----------------------------
# Departments
# -----------------------------
departments_data = [
  ["COMPUTER SCIENCE AND ENGINEERING", "CSE"],
  ["CIVIL ENGINEERING", "CIV"],
  ["ELECTRICAL AND ELECTRONICS ENGINEERING", "EEE"],
  ["ELECTRONICS AND COMMUNICATION ENGINEERING", "ECE"],
  ["MECHANICAL ENGINEERING", "MEC"],
  ["COMPUTER SCIENCE AND BUSINESS SYSTEMS", "CSB"],
  ["ARTIFICIAL INTELLIGENCE AND MACHINE LEARNING", "AIM"],
  ["DATA SCIENCE", "DS"]
]

departments = departments_data.to_h do |name, code|
  department = Department.create!(name: name, code: code)
  [code, department]
end

# -----------------------------
# Department Semesters
# 2 semesters for each department to keep semester association data.
# -----------------------------
department_semesters = {}

departments.each do |code, department|
  (1..2).each do |semester_no|
    department_semesters[[code, semester_no]] = DepartmentSemester.create!(
      department: department,
      semester_no: semester_no
    )
  end
end

