# -----------------------------
base_subjects = [
  ["01", "Communicative English", 3, "Theory"],
  ["02", "Linear Algebra & Calculus", 3, "Theory"],
  ["03", "Engineering Physics", 3, "Theory"],
  ["04", "Chemistry", 3, "Theory"],
  ["05", "Basic Civil & Mechanical Engineering", 3, "Theory"],
  ["06", "Engineering Physics Lab", 2, "Lab"],
  ["07", "Chemistry Lab", 2, "Lab"],
