  ["09", "Computer Programming Lab", 2, "Lab"],
  ["10", "Health and Wellness, Yoga and Sports", 2, "Lab"]
]

subjects_by_department = Hash.new { |hash, key| hash[key] = [] }

# Removed the old DBMS subject with department_semester_id: nil because Subject belongs_to :department_semester.

departments.each do |code, _department|
  base_subjects.each_with_index do |(number, name, credits, type), index|
    semester_no = index < 5 ? 1 : 2
    subject = Subject.create!(
      subject_code: "#{code}#{semester_no}#{number}",
      subject_name: name,
      credits: credits,
      subject_type: type,
      department_semester: department_semesters[[code, semester_no]]
    )
    subjects_by_department[code] << subject
  end
end

