# -----------------------------
# Marks helpers
# -----------------------------
def calculate_grade(final_total)
  case final_total
  when 90..100 then ["A++", 10.0]
  when 80...90 then ["A", 9.0]
  when 70...80 then ["B", 8.0]
  when 60...70 then ["C", 7.0]
  when 50...60 then ["D", 6.0]
  when 40...50 then ["E", 5.0]
  else ["F", 0.0]
  end
end

def build_mark_values(student_index, subject_index)
  i1_assignment = 3 + ((student_index + subject_index) % 3)
  i1_assessment = 10 + ((student_index + subject_index) % 6)
  i1_ethics = 3 + ((student_index + subject_index) % 3)
  i1_classwork = 3 + ((student_index + subject_index + 1) % 3)
  i1_total = i1_assignment + i1_assessment + i1_ethics + i1_classwork

  i2_assignment = 3 + ((student_index + subject_index + 1) % 3)
  i2_assessment = 10 + ((student_index + subject_index + 2) % 6)
  i2_ethics = 3 + ((student_index + subject_index + 2) % 3)
  i2_classwork = 3 + ((student_index + subject_index) % 3)
  i2_total = i2_assignment + i2_assessment + i2_ethics + i2_classwork

  best_internal = [i1_total, i2_total].max.to_f
  least_internal = [i1_total, i2_total].min.to_f
  final_internal = (best_internal * 0.75) + (least_internal * 0.25)
  external_exam = 30 + ((student_index * 7 + subject_index * 5) % 41)
  final_total = final_internal + external_exam
  grade, gpa = calculate_grade(final_total)

  {
    i1_assignment: i1_assignment,
    i1_assessment: i1_assessment,
    i1_ethics: i1_ethics,
    i1_classwork: i1_classwork,
    i1_total: i1_total.to_f,
    i2_assignment: i2_assignment,
    i2_assessment: i2_assessment,
    i2_ethics: i2_ethics,
    i2_classwork: i2_classwork,
    i2_total: i2_total.to_f,
    best_internal: best_internal,
    least_internal: least_internal,
    final_internal: final_internal.round(2),
    external_exam: external_exam,
    final_total: final_total.round(2),
    grade: grade,
    gpa: gpa,
    result: grade == "F" ? "FAIL" : "PASS"
  }
end

# -----------------------------
# Student Marks
# 10 mark records per student, one for each department subject.
# -----------------------------
students_by_department.each do |code, students|
  students.each_with_index do |student, student_index|
    subjects_by_department[code].first(10).each_with_index do |subject, subject_index|
      StudentMark.create!(
        build_mark_values(student_index, subject_index).merge(
          student: student,
          subject: subject
        )
      )
    end
  end
end

# -----------------------------
# Internal Marks
# 10 records retained and associated with subjects.
# -----------------------------
subjects_by_department.values.flatten.first(10).each_with_index do |subject, index|
  values = build_mark_values(index, index)
  InternalMark.create!(
    subject: subject,
    i1_assignment: values[:i1_assignment],
    i1_assessment: values[:i1_assessment],
    i1_ethics: values[:i1_ethics],
    i1_classwork: values[:i1_classwork],
    i1_total: values[:i1_total],
    i2_assignment: values[:i2_assignment],
    i2_assessment: values[:i2_assessment],
    i2_ethics: values[:i2_ethics],
    i2_classwork: values[:i2_classwork],
    i2_total: values[:i2_total],
    best_internal: values[:best_internal],
    least_internal: values[:least_internal],
    final_internal: values[:final_internal]
  )
end

# -----------------------------
# External Marks
# 10 records retained and associated with subjects.
# -----------------------------
subjects_by_department.values.flatten.first(10).each_with_index do |subject, index|
  values = build_mark_values(index, index)
  ExternalMark.create!(
    subject: subject,
    external_exam: values[:external_exam],
    final_total: values[:final_total],
    grade: values[:grade],
    gpa: values[:gpa],
    result: values[:result]
  )
end

